  "inlineSchema": "model Verification {\n  id        String   @id @default(uuid())\n  user_id   String\n  user      User     @relation(fields: [user_id], references: [id], onDelete: Cascade)\n  otpCode   String // Diganti dari token menjadi otp_code\n  expiresAt DateTime // Batas waktu OTP valid\n  createdAt DateTime @default(now())\n\n  // Mencegah ada otp_code dan email yang sama persis ganda di database\n  @@unique([user_id, otpCode])\n  @@map(\"verifications\")\n}\n\nmodel Assignment {\n  id String @id @default(uuid())\n\n  classId String\n  class   Class  @relation(fields: [classId], references: [id], onDelete: Cascade)\n\n  mentorId String\n  mentor   User   @relation(\"MentorAssignments\", fields: [mentorId], references: [id])\n\n  title          String\n  description    String?        @db.Text\n  submissionType SubmissionType\n  attachmentUrl  String? // Link soal (opsional)\n  due_date       DateTime\n\n  createdAt DateTime @default(now())\n\n  submissions AssignmentContent[]\n\n  @@map(\"assignments\")\n}\n\nmodel AssignmentContent {\n  id String @id @default(uuid())\n\n  assignmentId String\n  assignment   Assignment @relation(fields: [assignmentId], references: [id], onDelete: Cascade)\n\n  santriId String\n  santri   User   @relation(\"SantriSubmissions\", fields: [santriId], references: [id], onDelete: Cascade)\n\n  contentType    ContentType\n  fileUrl        String[]\n  score          Int?\n  mentorFeedback String?       @db.Text\n  status         GradingStatus @default(PENDING)\n\n  submittedAt DateTime @default(now())\n\n  @@unique([assignmentId, santriId])\n  @@map(\"assignment_content\")\n}\n\nmodel Attendance {\n  id String @id @default(uuid())\n\n  classId String\n  class   Class  @relation(fields: [classId], references: [id], onDelete: Cascade)\n\n  santriId String\n  santri   User   @relation(\"SantriAttendances\", fields: [santriId], references: [id], onDelete: Cascade)\n\n  mentorId String\n  mentor   User   @relation(\"MentorAttendances\", fields: [mentorId], references: [id])\n\n  date     DateTime         @db.Date\n  status   AttendanceStatus\n  notes    String?          @db.Text\n  imageUrl String? // Bukti kehadiran/sakit/izin\n\n  createdAt DateTime @default(now())\n\n  // Memastikan 1 santri hanya diabsen 1 kali per kelas per hari\n  @@unique([classId, santriId, date])\n  @@map(\"attendances\")\n}\n\nmodel Class {\n  id       String   @id @default(uuid())\n  divisiId String\n  division Division @relation(fields: [divisiId], references: [id], onDelete: Restrict)\n\n  name String\n\n  mentorId String\n  mentor   User   @relation(\"MentorClasses\", fields: [mentorId], references: [id])\n\n  createdAt DateTime @default(now())\n\n  attendances    Attendance[]\n  assignments    Assignment[]\n  santriProfiles SantriProfile[]\n\n  @@map(\"classes\")\n}\n\nmodel Division {\n  id          String   @id @default(uuid())\n  name        String // Misal: SD, SMP, SMA, Tahfidz\n  description String?  @db.Text\n  createdAt   DateTime @default(now())\n\n  classes Class[]\n\n  @@map(\"divisions\")\n}\n\nmodel SantriProfile {\n  id     String @id @default(uuid())\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  waliId String?\n  wali   User?   @relation(\"WaliToSantri\", fields: [waliId], references: [id])\n\n  phone     String?\n  birthDate DateTime? @db.Date\n  address   String?   @db.Text\n  photoUrl  String?\n\n  classId String?\n  class   Class?  @relation(fields: [classId], references: [id], onDelete: SetNull)\n\n  @@map(\"santri_profiles\")\n}\n\nmodel User {\n  id        String   @id @default(uuid())\n  nis       String?  @unique\n  fullName  String\n  email     String   @unique\n  password  String\n  phone     String? // Dibuat opsional (bisa null) karena mungkin tidak semua punya HP\n  role      Role\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  // Relasi (Ini otomatis dibuat oleh Prisma untuk back-reference)\n  verifications     Verification[]\n  santriProfile     SantriProfile?\n  mentorClasses     Class[]             @relation(\"MentorClasses\")\n  mentorAttendances Attendance[]        @relation(\"MentorAttendances\")\n  santriAttendances Attendance[]        @relation(\"SantriAttendances\")\n  mentorAssignments Assignment[]        @relation(\"MentorAssignments\")\n  santriSubmissions AssignmentContent[] @relation(\"SantriSubmissions\")\n\n  // Relasi Wali Santri\n  waliRelations   WaliSantriRelation[] @relation(\"WaliToRelation\")\n  santriRelations WaliSantriRelation[] @relation(\"SantriToRelation\")\n  santriUnderWali SantriProfile[]      @relation(\"WaliToSantri\")\n\n  @@map(\"users\")\n}\n\nmodel WaliSantriRelation {\n  id String @id @default(uuid())\n\n  waliId String\n  wali   User   @relation(\"WaliToRelation\", fields: [waliId], references: [id], onDelete: Cascade)\n\n  santriId String\n  santri   User   @relation(\"SantriToRelation\", fields: [santriId], references: [id], onDelete: Cascade)\n\n  name     String?\n  phone    String?\n  photoUrl String?\n  category WaliSantriCategory @default(OTHER)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Memastikan satu kombinasi wali dan anak tidak duplikat\n  @@unique([waliId, santriId])\n  @@map(\"wali_santri_relations\")\n}\n\n// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../../generated\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Role {\n  ADMIN\n  MENTOR\n  SANTRI\n  WALI_SANTRI\n}\n\nenum AttendanceStatus {\n  HADIR\n  SAKIT\n  IZIN\n  ALFA\n}\n\nenum SubmissionType {\n  TEXT\n  FILE\n}\n\nenum GradingStatus {\n  PENDING\n  GRADED\n}\n\nenum ContentType {\n  VIDEO\n  FOTO\n  TEXT\n}\n\nenum WaliSantriCategory {\n  AYAH\n  IBU\n  OTHER\n}\n"
